INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.6.110','cb','cb.adi.6','ЧБ Ади 6.110',110,'মিশ্র বোলে,—“সেহ পুত্ত্র তোমা’-সবাকার ।
যদি অপরাধ লহ,—শপথ আমার” ॥১১০॥','миш́ра боле, — ‘сеха путра тома̄’ саба̄ка̄ра
йади апара̄дха лаха, — ш́апатха а̄ма̄ра’',NULL,NULL),('cb.adi.6.111','cb','cb.adi.6','ЧБ Ади 6.111',111,'তা’-সবার সঙ্গে মিশ্র করি’ কোলাকুলি ।
গৃহে আইলেন মিশ্র হই’ কুতূহলী ॥১১১॥','та̄’саба̄ра сан̇ге миш́ра кари’ кола̄кули
гр̣хе а̄илена миш́ра хаи’ кутӯхалӣ',NULL,NULL),('cb.adi.6.112','cb','cb.adi.6','ЧБ Ади 6.112',112,'আর-পথে ঘরে গেলা প্রভু-বিশ্বম্ভর ।
হাথেতে মোহন পুঁথি যেন শশধর ॥১১২॥','а̄ра-патхе гхаре гела̄ прабху-виш́вамбхара
ха̄тхете мохана пун̇тхи, йена ш́аш́адхара',NULL,NULL),('cb.adi.6.113','cb','cb.adi.6','ЧБ Ади 6.113',113,'লিখন-কালির বিন্দু শোভে গৌর অঙ্গে ।
চম্পকে লাগিল যেন চারিদিকে ভৃঙ্গে ॥১১৩॥','ликхана-ка̄лира бинду ш́обхе гаура ан̇ге
чампаке ла̄гила йена ча̄ри-дике бхр̣н̇ге',NULL,NULL),('cb.adi.6.114','cb','cb.adi.6','ЧБ Ади 6.114',114,'“জননী!” বলিয়া প্রভু লাগিলা ডাকিতে ।
“তৈলা দেহ’ মোরে, যাই সিনান করিতে” ॥১১৪॥','‘джананӣ!’ балийа̄ прабху ла̄гила̄ д̣а̄ките
‘таила деха’ море, йа̄и сина̄на карите’',NULL,NULL),('cb.adi.6.115','cb','cb.adi.6','ЧБ Ади 6.115',115,'পুত্ত্রের বচন শুনি’ শচী হরষিত ।
কিছুই না দেখে অঙ্গে স্নানের চরিত ॥১১৫॥','путрера вачана ш́уни’ ш́ачӣ хараш̣ита
кичхуи на̄ декхе ан̇ге сна̄нера чарита',NULL,NULL),('cb.adi.6.116','cb','cb.adi.6','ЧБ Ади 6.116',116,'তৈল দিয়া শচীদেবী মনে মনে গণে’ ।
“বালিকারা কি বলিল, কিবা দ্বিজগণে ॥১১৬॥','таила дийа̄ ш́ачӣдевӣ мане-мане ган̣е’
‘ба̄лика̄ра̄ ки балила, киба̄ двиджа-ган̣е',NULL,NULL),('cb.adi.6.117','cb','cb.adi.6','ЧБ Ади 6.117',117,'লিখন-কালির বিন্দু আছে সব অঙ্গে ।
সেই বস্ত্র-পরিধান, সেই পুঁথি সঙ্গে” ॥১১৭॥','ликхана-ка̄лира бинду а̄чхе саба ан̇ге
сеи вастра паридха̄на, сеи пун̇тхи сан̇ге’',NULL,NULL),('cb.adi.6.118','cb','cb.adi.6','ЧБ Ади 6.118',118,'ক্ষণেকে আইলা জগন্নাথ মিশ্রবর।
মিশ্রে দেখি’ কোলেতে উঠিলা বিশ্বম্ভর ॥১১৮॥','кш̣ан̣еке а̄ила̄ джаганна̄тха миш́ра-вара
миш́рӣ декхи’ колете ут̣хила̄ виш́вамбхара',NULL,NULL),('cb.adi.6.119','cb','cb.adi.6','ЧБ Ади 6.119',119,'সেই আলিঙ্গনে মিশ্র বাহ্য নাহি জানে।
আনন্দে পূর্ণিত হৈলা পুত্ত্র-দরশনে ॥১১৯॥','сеи а̄лин̇гане миш́ра ба̄хйа на̄хи джа̄не
а̄нанде пӯрн̣ита хаила̄ путра-дараш́ане',NULL,NULL),('cb.adi.6.120','cb','cb.adi.6','ЧБ Ади 6.120',120,'মিশ্র দেখে সর্ব্ব-অঙ্গ ধূলায় ব্যাপিত ।
স্নানচিহ্ন না দেখিয়া হইলা বিস্মিত ॥১২০॥','миш́ра декхе сарва-ан̇га дхӯла̄йа вйа̄пита
сна̄на-чихна на̄ декхийа̄ хаила̄ висмита',NULL,NULL),('cb.adi.6.121','cb','cb.adi.6','ЧБ Ади 6.121',121,'মিশ্র বোলে,—“বিশ্বম্ভর, কি বুদ্ধি তোমার? ।
লোকেরে না দেহ’ কেনে স্নান করিবার? ॥১২১॥','миш́ра боле,—‘виш́вамбхара, ки буддхи тома̄ра?
локере на̄ деха’ кене сна̄на кариба̄ра?',NULL,NULL),('cb.adi.6.122','cb','cb.adi.6','ЧБ Ади 6.122',122,'বিষ্ণুপূজা-সজ্জ কেনে কর অপহার? ।
‘বিষ্ণু’ করিয়াও ভয় নাহিক তোমার?” ॥১২২॥','виш̣н̣у-пӯджа̄-саджджа кене кара апаха̄ра?
‘виш̣н̣у’ карийа̄о бхайа на̄хика тома̄ра?’',NULL,NULL),('cb.adi.6.123','cb','cb.adi.6','ЧБ Ади 6.123',123,'প্রভু বোলে,—“আজি আমি নাহি যাই স্নানে ।
আমার সংহতিগণ গেল আগুয়ানে ॥১২৩॥','прабху боле,—‘а̄джи а̄ми на̄хи йа̄и сна̄не
а̄ма̄ра сам̇хати-ган̣а гела̄ а̄гуйа̄не',NULL,NULL),('cb.adi.6.124','cb','cb.adi.6','ЧБ Ади 6.124',124,'সকল লোকেরে তারা করে অব্যভার ।
না গেলেও সবে দোষ কহেন আমার ॥১২৪॥','сакала локере та̄ра̄ каре авйабха̄ра
на̄ гелео сабе дош̣а кахена а̄ма̄ра',NULL,NULL),('cb.adi.6.125','cb','cb.adi.6','ЧБ Ади 6.125',125,'না গেলেও যদি দোষ কহেন আমার ।
সত্য তবে করিব সবারে অব্যভার” ॥১২৫॥','на̄ гелео йади дош̣а кахена а̄ма̄ра
сатйа табе кариба саба̄ре авйабха̄ра’',NULL,NULL),('cb.adi.6.126','cb','cb.adi.6','ЧБ Ади 6.126',126,'এত বলি’ হাসি’ প্রভু যা’ন গঙ্গাস্নানে ।
পুনঃ সেই মিলিলেন শিশুগণ-সনে ॥১২৬॥','эта бали’ ха̄си’ прабху йа̄’на ган̇га̄-сна̄не
пунах̣ сеи милилена ш́иш́у-ган̣а-сане',NULL,NULL),('cb.adi.6.127','cb','cb.adi.6','ЧБ Ади 6.127',127,'বিশ্বম্ভর দেখি’ সবে আলিঙ্গন করি’ ।
হাসয়ে সকল শিশু শুনিঞা চাতুরী ॥১২৭॥','виш́вамбхара декхи’сабе а̄лин̇гана кари’
ха̄сайе сакала ш́иш́у ш́унин̃а̄ ча̄турӣ',NULL,NULL),('cb.adi.6.128','cb','cb.adi.6','ЧБ Ади 6.128',128,'সবেই প্রশংসে,—“ভাল নিমাই চতুর ।
ভাল এড়াইলা আজি মারণ প্রচুর!” ॥১২৮॥','сабеи праш́ам̇се, — ‘бха̄ла нима̄и чатура
бха̄ла эд̣а̄ила̄ а̄джи ма̄ран̣а прачура!’',NULL,NULL),('cb.adi.6.129','cb','cb.adi.6','ЧБ Ади 6.129',129,'জলকেলি করে প্রভু সব-শিশু-সনে ।
হেথা শচী-জগন্নাথ মনে মনে গণে ॥১২৯॥','джала-кели каре прабху саба-ш́иш́у-сане
хетха̄ ш́ачӣ-джаганна̄тха мане-мане ган̣е’',NULL,NULL),('cb.adi.6.130','cb','cb.adi.6','ЧБ Ади 6.130',130,'“যে যে কহিলেন কথা, সেহ মিথ্যা নহে ।
তবে কেনে স্নানচিহ্ন কিছু নাহি দেহে? ॥১৩০॥','‘йе йе кахилена катха̄, сеха митхйа̄ нахе
табе кене сна̄на-чихна кичху на̄хи дехе?',NULL,NULL),('cb.adi.6.131','cb','cb.adi.6','ЧБ Ади 6.131',131,'সেইমত অঙ্গে ধূলা, সেইমত বেশ! ।
সেই পুঁথি, সেই বস্ত্র, সেইমত কেশ! ॥১৩১॥','сеи-мата ан̇ге дхӯла̄, сеи-мата веш́а!
сеи пун̇тхи, сеи вастра, сеи-мата кеш́а!',NULL,NULL),('cb.adi.6.132','cb','cb.adi.6','ЧБ Ади 6.132',132,'এ বুঝি মনুষ্য নহে শ্রীবিশ্বম্ভর! ।
মায়ারূপে কৃষ্ণ বা জন্মিলা মোর ঘর! ॥১৩২॥','э буджхи мануш̣йа нахе ш́рӣ-виш́вамбхара!
ма̄йа̄-рӯпе кр̣ш̣н̣а ва̄ джанмила̄ мора гхара!',NULL,NULL),('cb.adi.6.133','cb','cb.adi.6','ЧБ Ади 6.133',133,'কোন্মহাপুরুষ বা,—কিছুই না জানি” ।
হেন মতে চিন্তিতে আইলা দ্বিজমণি ॥১৩৩॥','кон маха̄пуруш̣а ва̄,—кичхуи на̄ джа̄ни’
хена-мате чинтите а̄ила̄ двиджа-ман̣и',NULL,NULL),('cb.adi.6.134','cb','cb.adi.6','ЧБ Ади 6.134',134,'পুত্ত্র-দরশনানন্দে ঘুচিল বিচার ।
স্নেহে পূর্ণ হৈলা দোঁহে, কিছু নাহি আর ॥১৩৪॥','путра-дараш́ана̄нанде гхучила вича̄ра
снехе пӯрн̣а хаила̄ дон̇хе, кичху на̄хи а̄ра',NULL,NULL),('cb.adi.6.135','cb','cb.adi.6','ЧБ Ади 6.135',135,'যেই দুইপ্রহর প্রভু যায় পড়িবারে ।
সেই দুই যুগ হই’ থাকে সে দোঁহারে ॥১৩৫॥','йеи дуи-прахара прабху йа̄йа пад̣иба̄ре
сеи дуи йуга хаи’ тха̄ке се дон̇ха̄ре',NULL,NULL),('cb.adi.6.136','cb','cb.adi.6','ЧБ Ади 6.136',136,'কোটি-রূপে কোটি-মুখে বেদে যদি কয় ।
তবু এ-দোঁহার ভাগ্যের নাহি সমুচ্চয় ॥১৩৬॥','кот̣и-рӯпе кот̣и-мукхе веде йади кайа
табу э-дон̇ха̄ра бха̄гйера на̄хи самуччайа',NULL,NULL),('cb.adi.6.137','cb','cb.adi.6','ЧБ Ади 6.137',137,'শচী-জগন্নাথ-পা’য়ে রহু নমস্কার ।
অনন্ত-ব্রহ্মানাথ পুত্ত্ররূপে যাঁর ॥১৩৭॥','ш́ачӣ-джаганна̄тха-па̄йе раху намаска̄ра
ананта-брахма̄н̣д̣а-на̄тха путра рӯпе йа̄н̇ра',NULL,NULL),('cb.adi.6.138','cb','cb.adi.6','ЧБ Ади 6.138',138,'এইমত ক্রীড়া করে বৈকুণ্ঠের রায় ।
বুঝিতে না পারে কেহ তাঁহান মায়ায় ॥১৩৮॥','эи-мата крӣд̣а̄ каре вайкунтхера ра̄йа
буджхите на̄ па̄ре кеха та̄н̇ха̄на̄ ма̄йа̄йа',NULL,NULL),('cb.adi.6.139','cb','cb.adi.6','ЧБ Ади 6.139',139,'শ্রীকৃষ্ণচৈতন্য-নিত্যানন্দচান্দ জান।
বৃন্দাবনদাস তছু পদযুগে গান ॥১৩৯॥','ш́рӣ кр̣ш̣н̣а-чаитанйа нитйа̄нанда-ча̄нда джа̄на
вр̣нда̄вана да̄са тачху пада-йуге га̄на',NULL,NULL),('cb.adi.7.1','cb','cb.adi.7','ЧБ Ади 7.1',1,'জয় জয় মহা-মহেশ্বর গৌরচন্দ্র ।
জয় জয় বিশ্বম্ভর-প্রিয়ভক্তবৃন্দ ॥১॥','джайа джайа маха̄-махеш́вара гаурачандра
джайа джайа виш́вамбхара-прийа-бхакта-вр̣нда',NULL,NULL),('cb.adi.7.2','cb','cb.adi.7','ЧБ Ади 7.2',2,'জয় জগন্নাথ-শচী-পুত্ত্র সর্ব্বপ্রাণ ।
কৃপা-দৃষ্ট্যে কর প্রভু সর্ব্ব-জীবে ত্রাণ ॥২॥','джайа джаганна̄тха-ш́ачӣ-путра сарва-пра̄н̣а
кр̣па̄-др̣ш̣т̣йе кара прабху сарва-джӣве тра̄н̣а',NULL,NULL),('cb.adi.7.3','cb','cb.adi.7','ЧБ Ади 7.3',3,'হেন মতে নবদ্বীপে শ্রীগৌরসুন্দর ।
বাল্যলীলা-ছলে করে প্রকাশ বিস্তর ॥৩॥','хена мате навадвӣпе ш́рӣ-гаурасундара
ба̄лйа-лӣла̄-чхале каре прака̄ш́а вистара',NULL,NULL),('cb.adi.7.4','cb','cb.adi.7','ЧБ Ади 7.4',4,'নিরন্তর চপলতা করে সবা-সনে ।
মা’য়ে শিখালেও প্রবোধ নাহি মানে ॥৪॥','нирантара чапалата̄ каре саба̄-сане
ма̄’йе ш́икха̄лео прабодха на̄хи ма̄не',NULL,NULL),('cb.adi.7.5','cb','cb.adi.7','ЧБ Ади 7.5',5,'শিখাইলে আরো হয় দ্বিগুণ চঞ্চল ।
গৃহে যাহা পায়, তাহা ভাঙ্গয়ে সকল ॥৫॥','ш́икха̄иле а̄ро хайа дви-гун̣а чан̃чала
гр̣хе йа̄ха па̄йа, та̄ха̄ бха̄н̇гайе сакала',NULL,NULL),('cb.adi.7.6','cb','cb.adi.7','ЧБ Ади 7.6',6,'ভয়ে আর কিছু না বোলয়ে বাপ-মা’য় ।
স্বচ্ছন্দে পরমানন্দে খেলায় লীলায় ॥৬॥','бхайе а̄ра кичху на̄ болайе ба̄па-ма̄’йа
сваччханде парама̄нанде кхела̄йа лӣла̄йа',NULL,NULL),('cb.adi.7.7','cb','cb.adi.7','ЧБ Ади 7.7',7,'আদিখণ্ড-কথা—যেন অমৃত-স্রবণ ।
যহিঁ, শিশুরূপে ক্রীড়া করে নারায়ণ ॥৭॥','а̄ди-кхан̣д̣а-катха̄ — йена амр̣та-ш́раван̣а
йахин̇ ш́иш́у-рӯпе крӣд̣а̄ каре на̄ра̄йан̣а',NULL,NULL),('cb.adi.7.8','cb','cb.adi.7','ЧБ Ади 7.8',8,'পিতা, মাতা, কাহারে না করে প্রভু ভয় ।
বিশ্বরূপ অগ্রজ দেখিলে নম্র হয় ॥৮॥','пита̄, ма̄та̄, ка̄ха̄ре на̄ каре прабху бхайа
виш́варӯпа аграджа декхиле намра хайа',NULL,NULL),('cb.adi.7.9','cb','cb.adi.7','ЧБ Ади 7.9',9,'প্রভুর অগ্রজ বিশ্বরূপ ভগবান্ ।
আজন্ম বিরক্ত, সর্ব্বগুণের নিধান ॥৯॥','прабхура аграджа виш́варӯпа бхагава̄н
а̄джанма виракта сарва-гун̣ера нидха̄на',NULL,NULL),('cb.adi.7.10','cb','cb.adi.7','ЧБ Ади 7.10',10,'সর্ব্বশাস্ত্রে সবে বাখানেন বিষ্ণু-ভক্তি ।
